│   ├── install-state.gz
│   ├── plugins
│   │   └── @yarnpkg
│   ├── releases
│   │   └── yarn-4.12.0.cjs
│   └── sdks
│       ├── eslint
│       ├── integrations.yml
│       ├── prettier
│       └── typescript
├── yarn.lock
└── .yarnrc.yml
```

